        a, b = map(int, input().split())
        cnt_a[a] = cnt_a.get(a,0)+1
        cnt_b[b] = cnt_b.get(b,0)+1
        if a not in problems_by_topic:
            problems_by_topic[a] = []
        problems_by_topic[a].append(b)

    total = n*(n-1)*(n-2)//6
    bad = 0
    for T, diffs in problems_by_topic.items():
        m = len(diffs)
        if m < 2:
            continue
        S = sum(cnt_b[d]-1 for d in diffs)
        bad += (m-1)*S

    print(total - bad)

